#include <bits/stdc++.h>
using namespace std;
int n,k,x[20],y[20],vis[2005],ans;
int arr[10];
queue<int>q;
int len;
void toarr(int k){
	memset(arr,0,sizeof(arr));
	len=0;
	do{
		arr[++len]=k%10;
		k/=10;
	}while (k);
}
int tonum(){
	int t=0;
	for(int i=1;i<=n;i++){
		t=t*10+arr[i];
	}
	return t;
}
void bfs(int m){
	q.push(m);
	vis[m]=1;
	while(!q.empty()){
		int u=q.front();
		q.pop();
		toarr(u);
		for(int i=1;i<=len;i++){
			for(int j=1;j<=k;j++){
				if(arr[i]==x[j]){
					arr[i]=y[j];
					int newnum=tonum();
					if(vis[newnum]==0){
						vis[newnum]=1;
						ans++;
						q.push(newnum);
					}
					arr[i]=x[j];
				}
			}
		}
	}
}
int main() {
	cin>>n>>k;
	for(int i=1;i<=k;i++){
		cin>>x[i]>>y[i];
	}
	bfs(n);
	cout<<(ans+1)*2;
	return 0;
}
